}

fun hasPair(arr: IntArray, target: Int): Boolean {
  val set = mutableSetOf<Int>()
  for (num in arr) {
    if (target - num in set) return true
    set.add(num)
  }
  return false
}

fun binarySearch(arr: IntArray, target: Int): Int {
  var l = 0; var r = arr.size - 1
  while (l <= r) {
    val mid = (l + r) / 2
    if (arr[mid] == target) return mid
    if (arr[mid] < target) l = mid + 1 else r = mid - 1
  }
  return -1
}

